# **VARIABLES**
#
# - A name to which we assign or give some values. They act as a placeholder which holds some value.
#
# **Rules for writing a variable name**

# 1- a variable name can't start with a digit/number

# syntax -> variablename = data/value which you want to assign

# 7a = 'aarav'
# 7a # error

# ### 2- a variable name can start with alphabet (lower case or upper case) or underscore

abc = 'Pawan'
abc

a = 10
print(a)

Ab = 'python'
Ab

_a1 = 'good morning'
_a1

# 3- a variable name can't have any special character or any special symbols (ex - @ , # , $ , % , ^ ,&...) except underscore

a_b = 'second class'
a_b

# a@b = 12
# a@b # error - because variable name can't have any special charcter or symbol

# 4- a variable name can't have any space between them

# a b = 'python'
# a b # error

# 5- variable can be alphanumeric (combination of alphabets and numbers)

abc12 = 'hello'
abc12

# 6- a variable name can't be a keyword

# while = 'a'
# while       # error

# Create a variable to store the name , age and marks of a student-
name = 'Manya'
a1 = 23
marks = 60
print('name of student -' ,name)
print('age is -' ,a1)
print('marks -',marks)

# how to print output in a single statement
print('name is -',name,',age is -',a1 , ',marks -',marks)

print(name , a1,marks)

# **DATA TYPES -** tells us the type of data a variable is holding
#
# - how to check datatype -> **type(variablename)**
#
# **what are the data types which are available in python-**
#
# 1- NUMERIC DATA -> every data which is related to numbers
#
# (ex - 3 , 4 ,500 , 10.5 , 99.5.....)
#
# - **Integer** , **Float** , **Complex**

# Integer -> whole number / numbers which are not in the form of decimals.
#
# - Can be positive or negative
#
# - ex - (100 , -28 , -1 , 450 , 14 .......)
#
# - it will return the datatype -----> **int**

a1 = 98
a1
type(a1)

b = -2908
print(b)
print(type(b))

# FLOAT -> any positive or negative decimal number/value
#
# - it will return -----> **float**

x = 9.75
type(x)

y1 = -2.7
print(type(y1))

# COMPLEX -> any number which is written in the form of a + bj
#
# - ex - (2+5j , 1+j , 10 + 1j....)
#
# - it will return the datatye --------> **complex**

x = 2+2j
x

type(x)

# a = 5 , bj = 2
# # two variable names can't be written or initialize in a single line

a2 = 2 - 7j
type(a2)

complex1=3+4j
complex2=complex(5,4)
print(complex1)
print(type(complex1))
print(complex2)
print(type(complex2))

# 2- STRINGS -> sequence of characters which is enclosed in single , double or triple quotes
#
# - it will return the datatype as -----> **str**

j = 'Manish'
print(j)
type(j)

b1 = 9.5
b2 = 10
b3 = 'hello python'
b4 = '60'
print(type(b1))
print(type(b2))
print(type(b3))
print(type(b4))

# 3- BOOLEAN DATA TYPE - It has two values - **True** and **False**
#
# - it will return the data type --------> **bool**

x = False
print(x)
print(type(x))

x1 = 'True'
print(type(x1))

