# **OPERATORS**
#
# - Symbols which are used to perform some task or some operations
#
# 1- Arithmetic Operators
#
# 2- Comparison Operators
#
# 3- Logical Operators
#
# 4- Assignment Operators
#
# 5- Membership Operators
#
# 6- Identity Operators

# **1- Arithemtic Operators -** used for performing mathematical calculations - ex - addition , subtraction , multiplication , divide , exponential , floor division , modulous

# addition
a1 = 100
a2 = 456
print(a1+a2)

# subtraction
a1-a2

# multiplication
x = 10
y = 10
print("multiplication -",x*y)

# division ---------> / return type ------float
a = 23
b = 2
print('division - ',a/b)

# floor division -------> // ----> return type ----------- int
a = 23
b = 2
print('floor division - ',a//b)

# modulous -> % -------- return the remainder
x1 = 37
x2 = 3
x1%x2

y1 = 37
print(y1%5)

# exponential operator ---->**---- returns the power/exponential value of a number
a = 2
b = 5
a**b   # (2**5)

print(5**8)

# **2- Comparison operators -** used to compare the values
#
# - return the answer in boolean values
#
# - equals ------> ==
#
# - not equals ------> !=
#
# - greater than -------> > , greater than equal to -----> >=
#
# - less than --------> < , less than equal to -------> <=

i = 982
j = 109
print(i==j)

i<j

i>j

i!=j

# **3- Assignment Operators -** used to assign or give some value

v1 = 'aarav'
print(v1)

v2 = v1
print(v2)

a = 50
a += 10 # a = a+10
print(a)

# **4- Logical Operators -** used to combine multiple statemnets or conditions
#
# - **and** , **or** , **not**
#
# - output will be boolean value

# and ---> if both the statements or conditions are true then only it will return true otherwise false

# ![image.png](data:image/png;base64,)

n1 = 80
n2 = 75
ans = (n1>5) and (n2>n1)
ans

# or ------> it returns true if atleast one statement is true other wise it will return false

# ![image.png](data:image/png;base64,)

c1 = 10
c2 = 5
(c1>c2) or (c2 <c1)

# not ------> it will reverse the output
# output = True ---> False
# output = False ---> True

a = 100
b = 70
res = (a>80) and (a>b)
print("result is -",res)
print(not(res))

